1	import { describe, it, expect } from "vitest";
2	import { quote, claim } from "./claim-office.js";
3	
4	describe("MHPCO Claims Office", () => {
5	  // Quote operation - base functionality
6	  it("should return 0 premium for empty item list", () => {
7	    expect(quote([])).toBe(0);
8	  });
9	  it("should calculate premium for single standard item (Sword)", () => {
10	    expect(quote([{ name: "Sword", type: "standard" }])).toBe(10);
11	  });
12	  it("should calculate premium for single standard item (Amulet)", () => {
13	    expect(quote([{ name: "Amulet", type: "standard" }])).toBe(10);
14	  });
15	  it("should calculate premium for single component", () => {
16	    expect(quote([{ name: "Mithril Component", type: "component" }])).toBe(5);
17	  });
18	  it("should sum premiums for multiple different items", () => {
19	    expect(quote([{ name: "Sword", type: "standard" }, { name: "Mithril Component", type: "component" }])).toBe(15);
20	  });
21	  it("should apply cursed modifier (+50%) to item premium", () => {
22	    expect(quote([{ name: "Sword", type: "standard", cursed: true }])).toBe(15);
23	  });
24	  it("should apply highly enchanted modifier (+30%) for items with enchantment >= 5", () => {
25	    expect(quote([{ name: "Sword", type: "standard", enchantment: 5 }])).toBe(13);
26	  });
27	  it("should apply first insurance modifier (+10%) to policy premium", () => {
28	    expect(quote([{ name: "Sword", type: "standard" }], { insurance: true })).toBe(11);
29	  });
30	  it("should apply loyalty modifier (-20%) for customers with >= 2 years", () => {
31	    expect(quote([{ name: "Sword", type: "standard" }], { years: 2 })).toBe(8);
32	  });
33	  it("should apply follow-up contract modifier (-15%) to policy premium", () => {
34	    expect(quote([{ name: "Sword", type: "standard" }], { followUp: true })).toBe(8.5);
35	  });
36	  it("should add 5G processing fee to final premium", () => {
37	    expect(quote([{ name: "Sword", type: "standard" }], { fiveG: true })).toBe(11);
38	  });
39	  it("should round premium up in MHPCO's favor", () => {
40	    expect(quote([{ name: "Sword", type: "standard" }], { years: 1, insurance: true })).toBe(12);
41	  });
42	
43	  // Claim operation - base functionality
44	  it("should deduct 100G deductible from claim payout", () => {
45	    expect(claim(1000, 500, 1000)).toBe(400);
46	  });
47	  it("should cap payout at 2x insurance value", () => {
48	    expect(claim(5000, 1000, 5000)).toBe(1900);
49	  });
50	  it("should apply 50% payout for enchantment >= 8", () => {
51	    expect(claim(1000, 500, 1000, 8)).toBe(450);
52	  });
