1	interface Item {
2	  name: string;
3	  type: "standard" | "component";
4	  cursed?: boolean;
5	  enchantment?: number;
6	}
7	
8	interface QuoteOptions {
9	  insurance?: boolean;
10	  years?: number;
11	  followUp?: boolean;
12	  fiveG?: boolean;
13	}
14	
15	const getBaseCostByType = (itemType: string): number => {
16	  return itemType === "component" ? 5 : 10;
17	};
18	
19	const calculateItemPremium = (item: Item): number => {
20	  let premium = getBaseCostByType(item.type);
21	  if (item.cursed) {
22	    premium += premium * 0.5;
23	  }
24	  if (item.enchantment !== undefined && item.enchantment >= 5) {
25	    premium += premium * 0.3;
26	  }
27	  return premium;
28	};
29	
30	const applyPercentageModifier = (amount: number, multiplier: number): number => {
31	  return amount + amount * multiplier;
32	};
33	
34	const applyInsuranceModifier = (premium: number, hasInsurance: boolean): number => {
35	  return hasInsurance ? applyPercentageModifier(premium, 0.1) : premium;
36	};
37	
38	const applyLoyaltyModifier = (premium: number, years?: number): number => {
39	  return years !== undefined && years >= 2 ? applyPercentageModifier(premium, -0.2) : premium;
40	};
41	
42	const applyFollowUpModifier = (premium: number, hasFollowUp: boolean): number => {
43	  return hasFollowUp ? applyPercentageModifier(premium, -0.15) : premium;
44	};
45	
46	const roundPremiumInMhpcosFavor = (premium: number, hasInsuranceAndYears: boolean): number => {
47	  return hasInsuranceAndYears ? Math.floor(premium) + 1 : premium;
48	};
49	
50	export function quote(items: Item[], options: QuoteOptions = {}): number {
51	  let total = 0;
52	  for (const item of items) {
53	    total += calculateItemPremium(item);
54	  }
55	  total = applyInsuranceModifier(total, options.insurance === true);
56	  total = applyLoyaltyModifier(total, options.years);
57	  total = applyFollowUpModifier(total, options.followUp === true);
58	  if (options.fiveG === true) {
59	    total += 1;
60	  }
61	  const hasInsuranceAndYears = options.insurance === true && options.years !== undefined;
62	  total = roundPremiumInMhpcosFavor(total, hasInsuranceAndYears);
63	  return total;
64	}
65	
66	export function claim(itemValue: number, insuredAmount: number, damageValue: number, enchantment?: number): number {
67	  const afterDeductible = damageValue - 100;
68	  if (enchantment !== undefined && enchantment >= 8) {
69	    return afterDeductible * 0.5;
70	  }
71	  const cap = 2 * insuredAmount;
72	  if (afterDeductible <= cap) {
73	    return afterDeductible - insuredAmount;
74	  }
75	  return cap - 100;
76	}
